pub struct Executor(Option<Pin<Box<dyn TypeErasedExecutor>>>);

impl Executor {
    pub fn new<F>(future: F) -> (Self, Arc<Spin<OutputHandle<F::Output>>>)
    where
        F: Future + Send + 'static,
